import{_ as t,y as a,a as c,o as i,ag as g,D as u}from"./chunks/framework.RVu0gECZ.js";const v=JSON.parse('{"title":"Thị trường đa nhà cung cấp","description":"","frontmatter":{},"headers":[],"relativePath":"multi-vendor-marketplace/introduction.md","filePath":"multi-vendor-marketplace/introduction.md","lastUpdated":1775737044000}'),o={name:"multi-vendor-marketplace/introduction.md"};function r(p,n,e,l,m,d){const h=a("ImagePopup");return i(),c("div",null,[n[0]||(n[0]=g('<h1 id="thi-truong-đa-nha-cung-cap" tabindex="-1">Thị trường đa nhà cung cấp <a class="header-anchor" href="#thi-truong-đa-nha-cung-cap" aria-label="Permalink to &quot;Thị trường đa nhà cung cấp&quot;">​</a></h1><p><a href="https://VNS.com/en/laravel-multi-vendor-marketplace/" target="_blank" rel="noreferrer">Chợ đa nhà cung cấp</a> biến một cửa hàng tiêu chuẩn thành một thị trường hoàn chỉnh, cho phép quản trị viên quản lý người bán, hoa hồng, phê duyệt sản phẩm và xử lý đơn đặt hàng, đồng thời cung cấp cho nhà cung cấp một trang tổng quan chuyên dụng để quản lý danh mục, đơn đặt hàng và giao dịch của họ.</p><h3 id="quan-ly-nha-cung-cap" tabindex="-1">Quản lý nhà cung cấp <a class="header-anchor" href="#quan-ly-nha-cung-cap" aria-label="Permalink to &quot;Quản lý nhà cung cấp&quot;">​</a></h3><p>Quản lý nhiều nhà cung cấp là điều quan trọng đối với bất kỳ thị trường trực tuyến nào. Nó giúp chủ sở hữu nền tảng (quản trị viên) theo dõi tất cả các nhà cung cấp (người bán), sản phẩm, đơn đặt hàng và thu nhập của họ một cách dễ dàng và có tổ chức.</p><p>Trong Multi Vendor Marketplace, hệ thống này được thiết kế thân thiện với người dùng đối với nhà cung cấp và rất hiệu quả đối với quản trị viên.</p><h3 id="quan-ly-đai-ly" tabindex="-1">Quản lý đại lý <a class="header-anchor" href="#quan-ly-đai-ly" aria-label="Permalink to &quot;Quản lý đại lý&quot;">​</a></h3><p>Hệ thống Quản lý đại lý cho phép các đại lý bán các sản phẩm đã có sẵn trên thị trường do Quản trị viên bổ sung.</p><p>Thay vì tạo danh sách mới từ đầu, đại lý có thể sử dụng các sản phẩm hiện có do Quản trị viên thêm vào, tùy chỉnh giá, số lượng, tình trạng sản phẩm và thêm mô tả mới.</p><p>Tính năng này giúp các đại lý tiết kiệm thời gian bằng cách sử dụng lại danh sách sản phẩm hiện có và duy trì thông tin sản phẩm nhất quán trên thị trường.</p><h3 id="quan-ly-đon-hang" tabindex="-1">Quản lý đơn hàng <a class="header-anchor" href="#quan-ly-đon-hang" aria-label="Permalink to &quot;Quản lý đơn hàng&quot;">​</a></h3><p>Quản lý đơn hàng trong Thị trường nhiều nhà cung cấp giúp người bán và quản trị viên theo dõi, quản lý và thực hiện đơn đặt hàng của khách hàng một cách dễ dàng.</p><p>Từ thời điểm người mua đặt hàng đến vận chuyển và giao hàng, mọi thứ đều được xử lý ở một nơi.</p><p>Nó đảm bảo xử lý trơn tru, cập nhật kịp thời và phối hợp tốt hơn giữa nhà cung cấp và người mua để có trải nghiệm mua sắm không gặp rắc rối.</p><h3 id="quan-ly-hoa-hong" tabindex="-1">Quản lý hoa hồng <a class="header-anchor" href="#quan-ly-hoa-hong" aria-label="Permalink to &quot;Quản lý hoa hồng&quot;">​</a></h3><p>Hệ thống Quản lý hoa hồng Marketplace tại VNS cho phép chủ sở hữu nền tảng (quản trị viên) thiết lập và quản lý tỷ lệ hoa hồng cho người bán một cách linh hoạt và rõ ràng.</p><p>Hệ thống này giúp thị trường kiếm được thu nhập ổn định và cũng mang lại cho quản trị viên khả năng đưa ra tỷ lệ hoa hồng đặc biệt cho người bán dưới dạng phần thưởng hoặc ưu đãi khi cần thiết.</p><h3 id="quan-ly-san-pham" tabindex="-1">Quản lý sản phẩm <a class="header-anchor" href="#quan-ly-san-pham" aria-label="Permalink to &quot;Quản lý sản phẩm&quot;">​</a></h3><p>Trong Multi Vendor Marketplace, tính năng quản lý Sản phẩm được thiết kế để cung cấp cho người bán quyền kiểm soát hoàn toàn đối với cửa hàng trực tuyến của họ. Nó cho phép người bán dễ dàng thêm sản phẩm mới, đặt giá, tải hình ảnh lên và cập nhật kho hàng.</p><p>Với các công cụ dễ sử dụng, người bán có thể nhanh chóng chỉnh sửa hoặc cập nhật sản phẩm bất cứ khi nào cần, đảm bảo danh sách của họ luôn chính xác và hấp dẫn.</p><h3 id="quan-ly-xep-hang" tabindex="-1">Quản lý xếp hạng <a class="header-anchor" href="#quan-ly-xep-hang" aria-label="Permalink to &quot;Quản lý xếp hạng&quot;">​</a></h3><p>Xếp hạng và đánh giá tạo dựng niềm tin trên thị trường trực tuyến, hướng dẫn khách hàng mua hàng và giúp người bán cải thiện dịch vụ của họ.</p><p>Trong Thị trường nhiều nhà cung cấp Laravel, Quản lý xếp hạng cho phép người mua để lại xếp hạng sao và phản hồi chi tiết về cả sản phẩm và người bán sau khi hoàn tất mua hàng.</p><h3 id="quan-ly-thanh-toan" tabindex="-1">Quản lý thanh toán <a class="header-anchor" href="#quan-ly-thanh-toan" aria-label="Permalink to &quot;Quản lý thanh toán&quot;">​</a></h3><p>Quản lý thanh toán trong Thị trường nhiều nhà cung cấp giúp cả người bán và quản trị viên xử lý tài chính một cách dễ dàng và rõ ràng. Người bán có thể nhanh chóng kiểm tra thu nhập của mình, xem chi tiết thanh toán cho đơn đặt hàng và yêu cầu thanh toán mà không gặp rắc rối.</p><p>Quản trị viên có thể dễ dàng theo dõi tất cả các khoản thanh toán, quản lý hoa hồng và đảm bảo các khoản thanh toán được an toàn và đúng thời hạn.</p>',25)),u(h,{src:"/images/multi-vendor-marketplace/multi-vendor-marketplace.webp",alt:"Super Admin Login"})])}const q=t(o,[["render",r]]);export{v as __pageData,q as default};
